-- 20260614_008_re_restore_overlap_class_dishes.sql
-- BUILD-01 correction: restore 104 class-dish options for the 13 overlap (non-primary)
-- meal classes and seed the 13 overlap-resolution guard rows. Prior import
-- (import_workbook.py:258) wrongly EXCLUDED dishes for allowed_as_weekly_primary=FALSE
-- classes AND never seeded re_meal_class_overlap_rules. Canonical workbook contract is
-- 1050 class-dish rows + 13 overlap rows. These classes are NEVER used as weekly primary
-- (verified: 0/20664 rows) so restoring dishes is safe; they serve add-on/combo expansion.
-- Additive only; idempotent via ON CONFLICT / NOT EXISTS guards.

ON CONFLICT (dish_option_id) DO NOTHING;

